import heapq

class Solution:
    def minNumberOfSeconds(self, mountainHeight, workerTimes):
        heap = [(t, 1, t) for t in workerTimes]
        heapq.heapify(heap)
        finish = 0
        for _ in range(mountainHeight):
            finish, cnt, t = heapq.heappop(heap)
            heapq.heappush(heap, (finish + t * (cnt + 1), cnt + 1, t))
        return finish

