from math import isqrt

class Solution:
    def minNumberOfSeconds(self, mountainHeight, workerTimes):
        def capacity(t, T):
            disc = t * t + 8 * t * T
            r = isqrt(disc)
            x = (r - t) // (2 * t)
            while t * x * (x + 1) > 2 * T:
                x -= 1
            while t * (x + 1) * (x + 2) <= 2 * T:
                x += 1
            return x

        def feasible(T):
            total = 0
            for t in workerTimes:
                total += capacity(t, T)
                if total >= mountainHeight:
                    return True
            return total >= mountainHeight

        lo, hi = 0, min(workerTimes) * mountainHeight * (mountainHeight + 1) // 2
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

