var minNumberOfSeconds = function(mountainHeight, workerTimes) {
    function bigSqrt(n) {
        if (n < 2n) return n;
        let x0 = n, x1 = (x0 + 1n) >> 1n;
        while (x1 < x0) {
            x0 = x1;
            x1 = (x0 + n / x0) >> 1n;
        }
        return x0;
    }
    function capacity(t, T) {
        const tB = BigInt(t), TB = T;
        const disc = tB * tB + 8n * tB * TB;
        const r = bigSqrt(disc);
        let x = (r - tB) / (2n * tB);
        while (tB * x * (x + 1n) > 2n * TB) x -= 1n;
        while (tB * (x + 1n) * (x + 2n) <= 2n * TB) x += 1n;
        return x;
    }
    const H = BigInt(mountainHeight);
    let lo = 0n;
    let hi = BigInt(Math.min(...workerTimes)) * H * (H + 1n) / 2n;
    function feasible(T) {
        let total = 0n;
        for (const t of workerTimes) {
            total += capacity(t, T);
            if (total >= H) return true;
        }
        return total >= H;
    }
    while (lo < hi) {
        const mid = (lo + hi) / 2n;
        if (feasible(mid)) hi = mid; else lo = mid + 1n;
    }
    return Number(lo);
};
